/**
 * @fileoverview ResourceList — explorer-style selectable resource table.
 *
 * Semantic {@code <table>} with generous vertical rhythm, flat rows (no grid lines),
 * rounded selection affordance, optional client-side sorting.
 *
 * @module module/ResourceList/index
 */

import { default as razyui } from '../../index.js';
import Icons from '../Icons.js';
import { setContent } from '../shared/setContent.js';
import { PART } from './constants.js';

const { getNestedValue } = razyui;

const DEFAULTS = {
    emptyMessage: 'No items',
    selection: 'none', // 'none' | 'single' | 'multiple'
    selectionCheckboxes: false,
    rowIdKey: 'id',
};

const ResourceList = class {
    /** @type {HTMLElement | null} */
    #host = null;
    /** @type {Record<string, unknown>} */
    #config = {};
    /** @type {Array<Record<string, unknown>>} */
    #columns = [];
    /** @type {unknown[]} */
    #data = [];
    /** @type {unknown[]} */
    #display = [];

    /** @type {ReturnType<razyui['spell']> | null} */
    #container = null;
    /** @type {ReturnType<razyui['spell']> | null} */
    #tbody = null;

    /** @type {string | null} */
    #sortCol = null;
    /** @type {'asc' | 'desc' | null} */
    #sortDir = null;

    /** @type {Set<string>} */
    #selected = new Set();

    #destroyed = false;
    #eventAC = new AbortController();

    /**
     * @param {string | HTMLElement} selector host element or selector
     * @param {Record<string, unknown>} [config]
     */
    constructor(selector, config = {}) {
        const el = razyui.isStr(selector) ? razyui(selector)[0] : selector;
        if (!el) {
            console.warn('ResourceList: element not found →', selector);
            return;
        }

        this.#host = el;
        this.#config = { ...DEFAULTS, ...config };
        if (this.#config.selectionCheckboxes == null) {
            this.#config.selectionCheckboxes = String(this.#config.selection) === 'multiple';
        }
        this.#columns = this.#normaliseColumns(config.columns || []);

        if (!this.#columns.length) {
            console.warn('ResourceList: columns required');
        }

        this.#buildDOM();

        const rows = config.data;
        if (Array.isArray(rows)) {
            this.setData(rows);
        }
    }

    /**
     * @param {object | unknown[]} raw
     */
    #normaliseColumns(raw) {
        /** @param {Record<string, unknown> | string} c */
        /** @param {string} [key] */
        const normalise = (c, key) => {
            if (typeof c === 'string') {
                return { key: c, label: c, sortable: true, html: false };
            }
            const obj = /** @type {Record<string, unknown>} */ (c);
            const k = String(key || obj.key || obj.name || obj.field || '');
            return {
                key: k,
                label: String(obj.label ?? obj.header ?? obj.key ?? key ?? ''),
                sortable: obj.sortable !== false,
                width: obj.width ?? null,
                minWidth: obj.minWidth ?? obj.min_width ?? null,
                align: obj.align ?? null,
                nowrap: !!obj.nowrap,
                ellipsis: !!obj.ellipsis,
                html: !!(obj.html || obj.printHTML),
            };
        };

        if (Array.isArray(raw)) {
            return raw.map((c) => (typeof c === 'string' ? normalise(c) : normalise(/** @type {Record<string, unknown>} */ (c))));
        }
        return Object.entries(/** @type {Record<string, unknown>} */ (raw)).map(([key, def]) => {
            if (typeof def === 'string') return /** @type {any} */ (normalise(def, key));
            return /** @type {any} */ (normalise(/** @type {Record<string, unknown>} */ (def), key));
        });
    }

    #selectionCheckboxesEnabled() {
        const mode = String(this.#config.selection || 'none');
        if (mode === 'none') return false;

        return !!this.#config.selectionCheckboxes;
    }

    #buildDOM() {
        const $ = razyui;

        this.#container = $.spell('div.resource-list-container', true);
        PART.CONTAINER.apply(this.#container);

        const wrap = $.spell('div.resource-list-wrapper', true);
        PART.WRAPPER.apply(wrap);

        const table = $.spell('table.resource-list-table', true);
        PART.TABLE.apply(table);

        const thead = $.spell('thead', true);
        PART.THEAD.apply(thead);

        const hr = $.spell('tr', true);
        if (this.#selectionCheckboxesEnabled()) {
            const thSel = $.spell('th.resource-list-th-select', true).attr('data-key', '__select');
            PART.THEAD_TH.apply(thSel);
            thSel.css('width', '2.25rem');
            thSel.css('min-width', '2.25rem');
            thSel.css('text-align', 'center');
            thSel.attr('aria-label', 'Select');
            if (String(this.#config.selection) === 'multiple') {
                const master = document.createElement('input');
                master.type = 'checkbox';
                master.className = 'resource-list-select-all';
                master.setAttribute('aria-label', 'Select all rows');
                thSel[0].appendChild(master);
            }
            hr.append(thSel);
        }
        for (const col of this.#columns) {
            const th = $.spell('th', true).attr('data-key', col.key).text(col.label);
            PART.THEAD_TH.apply(th);
            if (col.width) th.css('width', typeof col.width === 'number' ? `${col.width}px` : String(col.width));
            if (col.minWidth) th.css('min-width', typeof col.minWidth === 'number' ? `${col.minWidth}px` : String(col.minWidth));
            if (col.align) th.css('text-align', String(col.align));
            if (col.sortable) {
                th.addClass('is-sortable');
                const icon = $.spell('span.resource-list-sort-icon', true);
                PART.SORT_ICON.apply(icon);
                icon.html(Icons.svg('arrow-up-down', { size: 12, strokeWidth: 2 }));
                th.append(icon);
            }
            hr.append(th);
        }
        thead.append(hr);

        this.#tbody = $.spell('tbody', true);

        table.append(thead, this.#tbody);
        wrap.append(table);
        this.#container.append(wrap);

        $(this.#host).html('').append(this.#container);

        this.#container.on(
            'click',
            (ev) => {
                const master = ev.target.closest('input.resource-list-select-all');
                if (master instanceof HTMLInputElement) {
                    ev.stopPropagation();
                    const mode = String(this.#config.selection || 'none');
                    if (mode !== 'multiple') return;
                    const list = Array.isArray(this.#display) ? this.#display : [];
                    if (master.checked) {
                        for (const row of list) {
                            const rk = this.#stableRowKey(row);
                            if (rk) this.#selected.add(rk);
                        }
                    } else {
                        this.#selected.clear();
                    }
                    this.#syncRowSelectionClasses();
                    this.#emitSelection();
                    return;
                }

                const rowCb = ev.target.closest('input.resource-list-row-select');
                if (rowCb instanceof HTMLInputElement) {
                    ev.stopPropagation();
                    const tr = rowCb.closest('tr.resource-list-row[data-row-key]');
                    if (!(tr instanceof HTMLElement)) return;
                    const key = tr.dataset.rowKey || '';
                    if (!key) return;
                    const mode = String(this.#config.selection || 'none');
                    if (mode === 'single') {
                        this.#selected.clear();
                        if (rowCb.checked) this.#selected.add(key);
                    } else if (rowCb.checked) {
                        this.#selected.add(key);
                    } else {
                        this.#selected.delete(key);
                    }
                    this.#syncRowSelectionClasses();
                    this.#emitSelection();
                    return;
                }

                const th = ev.target.closest('th[data-key]');
                if (th && razyui(th).hasClass('is-sortable')) {
                    this.#toggleSort(th.dataset.key || '');
                    return;
                }
                const tr = ev.target.closest('tr.resource-list-row[data-row-key]');
                if (!(tr instanceof HTMLElement)) return;
                if (ev.target.closest('a,button,input,textarea,select,label')) return;

                const mode = String(this.#config.selection || 'none');
                if (mode === 'none') return;

                const key = tr.dataset.rowKey || '';
                if (!key) return;

                if (mode === 'single') {
                    this.#selected.clear();
                    this.#selected.add(key);
                } else {
                    if (this.#selected.has(key)) this.#selected.delete(key);
                    else this.#selected.add(key);
                }
                this.#syncRowSelectionClasses();
                this.#emitSelection();
            },
            { signal: this.#eventAC.signal },
        );
    }

    /** @param {string} key */
    #toggleSort(key) {
        const col = this.#columns.find((c) => c.key === key);
        if (!col || !col.sortable) return;

        if (this.#sortCol === key) {
            this.#sortDir = this.#sortDir === 'asc' ? 'desc' : this.#sortDir === 'desc' ? null : 'asc';
            if (!this.#sortDir) this.#sortCol = null;
        } else {
            this.#sortCol = key;
            this.#sortDir = 'asc';
        }

        this.#applySortAndRenderHeaders();
        this.#renderBody();
    }

    #applySortAndRenderHeaders() {
        const $ = razyui;
        const thead = this.#container?.find('thead');
        if (!thead || !thead.length) return;

        thead.find('th[data-key]').each((thEl) => {
            const $th = $(thEl);
            $th.removeClass('is-sort-asc is-sort-desc');
            const icon = $th.find('.resource-list-sort-icon');
            if (!icon.length) return;
            const k = thEl.dataset.key;

            if (k === this.#sortCol && this.#sortDir) {
                $th.addClass(this.#sortDir === 'asc' ? 'is-sort-asc' : 'is-sort-desc');
                icon.html(Icons.svg(this.#sortDir === 'asc' ? 'sort-asc' : 'sort-desc', { size: 12, strokeWidth: 2 }));
            } else if ($th.hasClass('is-sortable')) {
                icon.html(Icons.svg('arrow-up-down', { size: 12, strokeWidth: 2 }));
            }
        });

        let rows = [...this.#data];
        if (this.#sortCol && this.#sortDir) {
            const sk = this.#sortCol;
            const dir = this.#sortDir;
            rows.sort((a, b) => {
                let va = getNestedValue(a, sk) ?? '';
                let vb = getNestedValue(b, sk) ?? '';
                if (razyui.isPO(va)) va = va.value ?? va.label ?? '';
                if (razyui.isPO(vb)) vb = vb.value ?? vb.label ?? '';
                if (typeof va === 'number' && typeof vb === 'number') {
                    return dir === 'asc' ? va - vb : vb - va;
                }
                va = String(va).toLowerCase();
                vb = String(vb).toLowerCase();
                if (va < vb) return dir === 'asc' ? -1 : 1;
                if (va > vb) return dir === 'asc' ? 1 : -1;
                return 0;
            });
        }
        this.#display = rows;
    }

    /**
     * Stable identity for selection — uses {@code rowIdKey} when present; otherwise the row's
     * index in the authoritative {@link #data} array (survives client-side reorder).
     *
     * @param {unknown} row
     */
    #stableRowKey(row) {
        const rk = String(this.#config.rowIdKey ?? DEFAULTS.rowIdKey);
        if (razyui.isPO(row) && rk in row && row[rk] != null && row[rk] !== '') {
            return String(row[rk]);
        }
        const i = this.#data.indexOf(row);
        return i >= 0 ? `__idx_${i}` : '__unknown';
    }

    #renderBody() {
        const $ = razyui;
        if (!this.#tbody) return;

        this.#tbody.html('');

        const list = Array.isArray(this.#display) ? this.#display : [];
        const selMode = String(this.#config.selection || 'none');

        if (!list.length) {
            const tr = $.spell('tr.resource-list-empty-row', true);
            PART.EMPTY_ROW.apply(tr);
            const colSpan = Math.max(1, this.#columns.length + (this.#selectionCheckboxesEnabled() ? 1 : 0));
            const td = $.spell('td', true).attr('colspan', colSpan);
            td.text(String(this.#config.emptyMessage ?? DEFAULTS.emptyMessage));
            tr.append(td);
            this.#tbody.append(tr);
            return;
        }

        const fragOwner = document.createDocumentFragment();

        list.forEach((row) => {
            const rk = this.#stableRowKey(row);
            const tr = $.spell('tr.resource-list-row', true).attr('data-row-key', rk).attr('data-index', String(this.#data.indexOf(row)));

            PART.TBODY_TR.apply(tr);
            if (selMode !== 'none') tr.addClass('is-selectable');

            const selected = this.#selected.has(rk);
            tr.attr('aria-selected', selected ? 'true' : 'false');
            if (selected) tr.addClass('is-selected');

            if (this.#selectionCheckboxesEnabled()) {
                const tdSel = $.spell('td.resource-list-td-select', true);
                PART.TBODY_TD.apply(tdSel);
                tdSel.css('width', '2.25rem');
                tdSel.css('min-width', '2.25rem');
                tdSel.css('text-align', 'center');
                const cb = document.createElement('input');
                cb.type = 'checkbox';
                cb.className = 'resource-list-row-select';
                cb.checked = selected;
                cb.setAttribute('aria-label', 'Select row');
                tdSel[0].appendChild(cb);
                tr.append(tdSel);
            }

            for (const col of this.#columns) {
                const td = $.spell('td', true);
                PART.TBODY_TD.apply(td);
                if (col.align) td.css('text-align', String(col.align));
                if (col.nowrap) td.addClass('is-nowrap');
                if (col.ellipsis) td.addClass('is-ellipsis');

                const rawVal = getNestedValue(row, col.key);
                if (col.html) {
                    setContent(td, rawVal != null ? String(rawVal) : '');
                } else if (rawVal != null && razyui.isPO(rawVal) && ('label' in rawVal || 'value' in rawVal)) {
                    td.text(String(rawVal.label ?? rawVal.value ?? ''));
                } else {
                    td.text(rawVal != null ? String(rawVal) : '');
                }

                tr.append(td);
            }

            fragOwner.append(tr[0]);
        });

        this.#tbody[0].appendChild(fragOwner);
    }

    #syncRowSelectionClasses() {
        const $ = razyui;
        if (!this.#tbody) return;
        const rows = this.#tbody.find('tr.resource-list-row[data-row-key]');
        rows.each((trEl) => {
            const key = trEl.dataset.rowKey || '';
            const on = key && this.#selected.has(key);
            const $tr = $(trEl);
            $tr.toggleClass('is-selected', !!on);
            $tr.attr('aria-selected', on ? 'true' : 'false');
            const cb = trEl.querySelector('input.resource-list-row-select');
            if (cb instanceof HTMLInputElement) cb.checked = !!on;
        });

        if (this.#selectionCheckboxesEnabled() && String(this.#config.selection) === 'multiple') {
            const master = this.#container?.find('input.resource-list-select-all')[0];
            if (master instanceof HTMLInputElement) {
                const list = Array.isArray(this.#display) ? this.#display : [];
                const total = list.length;
                const picked = list.filter((row) => this.#selected.has(this.#stableRowKey(row))).length;
                master.indeterminate = picked > 0 && picked < total;
                master.checked = total > 0 && picked === total;
            }
        }
    }

    #emitSelection() {
        const ids = [...this.#selected];
        this.#host?.dispatchEvent(
            new CustomEvent('rui-resource-list:selectionchange', {
                bubbles: true,
                detail: { ids, keys: ids },
            }),
        );
    }

    /** @param {unknown[]} rows */
    setData(rows) {
        if (this.#destroyed) return;
        this.#data = Array.isArray(rows) ? [...rows] : [];
        this.#applySortAndRenderHeaders();
        this.#renderBody();
    }

    getData() {
        return [...this.#data];
    }

    /** @param {string[]} ids */
    setSelectedIds(ids) {
        if (this.#destroyed) return;
        const mode = String(this.#config.selection || 'none');
        if (mode === 'none') return;

        this.#selected.clear();
        for (const id of ids || []) {
            const s = String(id);
            if (s) this.#selected.add(s);
            if (mode === 'single') break;
        }
        this.#syncRowSelectionClasses();
        this.#emitSelection();
    }

    getSelectedIds() {
        return [...this.#selected];
    }

    getControl() {
        const self = this;
        return {
            setData: (d) => self.setData(d),
            getData: () => self.getData(),
            setSelectedIds: (ids) => self.setSelectedIds(ids),
            getSelectedIds: () => self.getSelectedIds(),
            destroy: () => self.destroy(),
            get element() {
                return self.#host;
            },
            get destroyed() {
                return self.#destroyed;
            },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC.abort();
        if (this.#container) this.#container.detach();
        this.#container = null;
        this.#tbody = null;
    }
};

export default ResourceList;
